func (d ResourcePaths) FromTargetPath(targetPath string) ResourcePaths {
	targetPath = filepath.ToSlash(targetPath)
	dir, file := path.Split(targetPath)
	dir = paths.ToSlashPreserveLeading(dir)
	if dir == "/" {
		dir = ""
	}
	d.Dir = dir
	d.File = file
	d.BaseDirLink = ""
	d.BaseDirTarget = ""

	return d
}
